-- STEP 1: query [kommuner]
SELECT kommunenummer, kommunenavn, omrade, ST_SRID(omrade) AS omrade_srid FROM kommuner_627ee106072240e99d2b21ec4717bf01.kommune WHERE kommunenavn ILIKE 'Kristiansand' OR kommunenavn ILIKE 'Kristiansand%';

-- STEP BOUNDARY --

-- STEP 2: query [stormflohavniva]
